#pragma once
#define BATTERIES_RANDOM_ZIPF_HPP

#include <batteries/config.hpp>
//
#include <batteries/algo/parallel_accumulate.hpp>
#include <batteries/algo/parallel_copy.hpp>
#include <batteries/algo/parallel_running_total.hpp>
#include <batteries/assert.hpp>
#include <batteries/int_types.hpp>

#include <boost/range/irange.hpp>

#include <cmath>
#include <random>
#include <vector>

namespace batt {

//+++++++++++-+-+--+----- --- -- -  -  -   -
// Based on code from https://stackoverflow.com/a/48279287
// Posted by Masoud Kazemi
// Retrieved 2026-04-27, License - CC BY-SA 3.0
//+++++++++++-+-+--+----- --- -- -  -  -   -

template <typename IntT>
class ZipfIntDistribution
{
   public:
    using value_type = IntT;

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    static constexpr usize kDefaultMinParallelTaskSize = 32768;

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    explicit ZipfIntDistribution(double alpha, IntT min_value, IntT max_value) noexcept
        : alpha_{alpha}
        , min_value_{min_value}
        , max_value_{max_value}
    {
        BATT_CHECK_GE(this->max_value_, this->min_value_);
        const isize n = static_cast<isize>(this->max_value_ - this->min_value_) + 1;

        // Compute normalization constant.
        //
        double c = 0;
        for (isize i = 1; i <= n; ++i) {
            c = c + (1.0 / std::pow((double)i, alpha));
        }
        c = 1.0 / c;

        // Cache the prefix-sum of probability per value in the distribution.
        //
        this->sum_of_probabilities_.resize(n + 1);
        this->sum_of_probabilities_[0] = 0;
        for (isize i = 1; i <= n; ++i) {
            this->sum_of_probabilities_[i] =
                this->sum_of_probabilities_[i - 1] + c / std::pow((double)i, alpha);
        }
    }

    explicit ZipfIntDistribution(double alpha, IntT min_value, IntT max_value,
                                 WorkerPool& worker_pool) noexcept
        : alpha_{alpha}
        , min_value_{min_value}
        , max_value_{max_value}
    {
        BATT_CHECK_GE(this->max_value_, this->min_value_);

        auto params = WorkSliceParams{
            .min_task_size = TaskSize{kDefaultMinParallelTaskSize},
            .max_tasks = TaskCount{worker_pool.size()},
        };

        const isize n = static_cast<isize>(this->max_value_ - this->min_value_) + 1;
        const auto i_range = boost::irange<isize>(0, n + 1);

        // Compute normalization constant.
        //
        const double c = 1.0 / parallel_accumulate(
                                   worker_pool, std::begin(i_range), std::end(i_range), double{0.0},
                                   [alpha](double accumulator, isize i) -> double {
                                       if (i == 0) {
                                           return accumulator;
                                       }
                                       return accumulator + (1.0 / std::pow((double)i, alpha));
                                       ;
                                   },
                                   /*identity=*/double{0.0}, params);

        // Cache the prefix-sum of probability per value in the distribution.
        //
        BasicRunningTotal<double> total = parallel_running_total(
            worker_pool, std::next(std::begin(i_range)), std::end(i_range),
            [c, alpha](isize i) -> double {
                return c / std::pow((double)i, alpha);
            },
            params);

        this->sum_of_probabilities_.resize(total.size());
        parallel_copy(worker_pool, total.begin(), total.end(), this->sum_of_probabilities_.begin(), params);
    }

    double alpha() const noexcept
    {
        return this->alpha_;
    }

    usize size() const noexcept
    {
        return this->sum_of_probabilities_.size() - 1;
    }

    IntT min_value() const noexcept
    {
        return this->min_value_;
    }

    IntT max_value() const noexcept
    {
        return this->max_value_;
    }

    template <typename R>
    IntT operator()(R& random_source) noexcept
    {
        // Pull a uniform random number (0 < z < 1)
        //
        const double z = [this, &random_source] {
            for (;;) {
                double z = this->pick_z_(random_source);
                if (z != 0 && z != 1) {
                    return z;
                }
            }
        }();

        // Map z to the value
        //
        const usize zipf_value = [this, z] {
            usize low = 1, high = this->sum_of_probabilities_.size() - 1;
            for (;;) {
                const usize mid = floor((low + high) / 2);
                if (this->sum_of_probabilities_[mid] >= z && this->sum_of_probabilities_[mid - 1] < z) {
                    return mid;
                } else if (this->sum_of_probabilities_[mid] >= z) {
                    high = mid - 1;
                } else {
                    low = mid + 1;
                }
                BATT_CHECK_LE(low, high);
            }
        }();

        // Assert that zipf_value is between 1 and N
        //
        BATT_CHECK_IN_RANGE(1, zipf_value, this->sum_of_probabilities_.size());

        return this->min_value_ + (zipf_value - 1);
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -
   private:
    double alpha_;
    IntT min_value_;
    IntT max_value_;
    std::vector<double> sum_of_probabilities_;
    std::uniform_real_distribution<double> pick_z_{0, 1};
};

}  // namespace batt
